external_knowledge:
- 'More populous countries' in the context refers to countries with larger populations;
- 'Total inhabitants' refers to the sum of the population;
- 'Total cases' means the sum of all confirmed cases;
- 'Fatalities' are the number of deaths;
- 'Recoveries' represent the sum of all recoveries;
- 'Ongoing infections' are the total active cases.

sql:
SELECT pd.data_id, pd.observation_date, pd.confirmed, pd.deaths, pd.recovered, pd.active_cases, r.region_name, r.country_id, r.province_id
FROM pandemic_data pd
INNER JOIN regions r ON pd.region_id = r.region_id;
